    10→import org.springframework.web.bind.annotation.RequestMapping;
    11→import org.springframework.web.bind.annotation.RequestMethod;
    12→import org.springframework.web.bind.annotation.RequestParam;
    13→import org.springframework.web.bind.annotation.RestController;
    14→import org.springframework.web.reactive.function.client.WebClient;
    15→import org.springframework.web.reactive.function.client.WebClientResponseException;
    16→import reactor.core.publisher.Mono;
    17→import java.net.URI;
    18→import java.net.URISyntaxException;
    19→import java.util.List;
    20→
    21→@RestController
    22→@RequestMapping("/proxy")
    23→public class ProxyController {
    24→    // Block headers that can trigger origin restrictions on exchanges
    25→    private static final List<String> BLOCKED=List.of(
    26→        "host",
    27→        "content-length",
    28→        "transfer-encoding",
    29→        "connection",
    30→        "accept-encoding",
    31→        "origin",
    32→        "referer",
    33→        "sec-fetch-site",
    34→        "sec-fetch-mode",
    35→        "sec-fetch-dest",
    36→        "sec-fetch-user"
    37→    );
    38→    // Strip CORS headers from upstream responses — let Spring's CorsFilter handle them
    39→    private static final List<String> BLOCKED_RESP=List.of(
    40→        "transfer-encoding",
    41→        "access-control-allow-origin",
    42→        "access-control-allow-methods",
    43→        "access-control-allow-headers",
    44→        "access-control-expose-headers",
    45→        "access-control-allow-credentials",
    46→        "access-control-max-age"
    47→    );
    48→    private final WebClient client=WebClient.builder()
    49→        .defaultHeader("User-Agent","Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36")
    50→        .defaultHeader("Accept","application/json")
    51→        .defaultHeader("Accept-Encoding","identity")
    52→        .codecs(c->c.defaultCodecs().maxInMemorySize(4*1024*1024)).build();
    53→    @RequestMapping(value="/**",method={RequestMethod.GET,RequestMethod.POST,RequestMethod.PUT,RequestMethod.DELETE,RequestMethod.OPTIONS})
    54→    public Mono<ResponseEntity<String>> proxy(@RequestBody(required=false) String body,@RequestHeader HttpHeaders headers,@RequestParam(name="_target") String target,HttpServletRequest request){
    55→        HttpMethod method = HttpMethod.valueOf(request.getMethod());
    56→        String safeTarget;
    57→        try {
    58→            safeTarget = validateTarget(target);
    59→        } catch (IllegalArgumentException e) {
    60→            return Mono.just(ResponseEntity.badRequest().body("{\"error\":\"" + e.getMessage() + "\"}"));
    61→        }
    62→
    63→        System.out.println("[PROXY] "+method+" -> "+safeTarget);
    64→        if (method == HttpMethod.OPTIONS) {
    65→            return Mono.just(ResponseEntity.ok().build());
    66→        }
    67→
    68→        WebClient.RequestBodySpec req=client.method(method).uri(URI.create(safeTarget))
    69→            .headers(h->{
    70→                headers.forEach((name,values)->{if(BLOCKED.stream().noneMatch(b->b.equalsIgnoreCase(name)))values.forEach(v->h.add(name,v));});
    71→            });
    72→        if(body!=null&&!body.isBlank())req.contentType(MediaType.APPLICATION_JSON).bodyValue(body);
    73→        return req.retrieve().toEntity(String.class)
    74→            .map(entity -> {
    75→                HttpHeaders out = new HttpHeaders();
    76→                entity.getHeaders().forEach((k, v) -> {
    77→                    if (BLOCKED_RESP.stream().noneMatch(b -> b.equalsIgnoreCase(k))) out.put(k, v);
    78→                });
    79→                return ResponseEntity.status(entity.getStatusCode()).headers(out).body(entity.getBody());
    80→            })
    81→            .onErrorResume(WebClientResponseException.class,e->{
    82→                System.out.println("[PROXY] "+e.getStatusCode()+" body: "+e.getResponseBodyAsString());
    83→                return Mono.just(ResponseEntity.status(e.getStatusCode()).body(e.getResponseBodyAsString()));
    84→            })
    85→            .onErrorResume(e->{
    86→                System.err.println("[PROXY] Erro: "+e.getMessage());
    87→                return Mono.just(ResponseEntity.status(502).body("{\"error\":\""+e.getMessage()+"\"}"));
    88→            });
    89→    }
    90→
    91→    private String validateTarget(String target) {
    92→        try {
    93→            URI uri = new URI(target);
    94→            String scheme = uri.getScheme();
    95→            if (scheme == null || (!"https".equalsIgnoreCase(scheme) && !"http".equalsIgnoreCase(scheme))) {
    96→                throw new IllegalArgumentException("invalid target scheme");
    97→            }
    98→            if (uri.getHost() == null) {
    99→                throw new IllegalArgumentException("invalid target host");
   100→            }
   101→            return uri.toString();
   102→        } catch (URISyntaxException e) {
   103→            throw new IllegalArgumentException("invalid target uri");
   104→        }
   105→    }
   106→}
