### 5.4 Implementação de placeOrderMEXC()
```javascript
async function placeOrderMEXC(c, sym, side, qty, price, isSpot) {
  const ts = Date.now().toString();
  const sf = sym.replace('/', '');
  if (isSpot) {
    const bodyObj = { symbol: sf, side: side.UP(), type: 'LIMIT', quantity: String(qty), price: String(price) };
    const p = 'timestamp=' + ts + '&recvWindow=5000';
    const sig = await hmacHex(p, c.secret);
    const r = await apiFetch('https://api.mexc.com/api/v3/order?' + p + '&signature=' + sig, 
      { body: JSON.stringify(bodyObj) });
    const d = await r.json();
    if (d.code !== 200) throw new Error('MEXC: ' + d.msg);
    return { orderId: d.orderId, ... };
  } else {
    // Futures: contract.mexc.com
    const strSign = c.key + ts;
    const sig = await hmacHex(strSign, c.secret);
    const bodyObj = { symbol: sf + '_USDT', side: side === 'BUY' ? 1 : 3, ... };
    const r = await apiFetch('https://futures.mexc.com/api/v1/private/order/create', ...);
    const d = await r.json();
    if (!d.success) throw new Error('MEXC Fut: ' + d.message);
    return { orderId: d.data, ... };
  }
}
```

**Problemas:**
- ⚠️ `d.orderId` pode ser undefined se response falhar
- ⚠️ Spot vs Futures têm diferentes estruturas - fácil confundir

